public class BasicCasting {
    public static void main(String[] args) {
        // Widening: automatic, no cast needed
        int myInt = 100;
        long myLong = myInt;       // int → long (widening)
        float myFloat = myLong;    // long → float (widening)
        double myDouble = myFloat; // float → double (widening)

        System.out.println("int    : " + myInt);
        System.out.println("long   : " + myLong);
        System.out.println("float  : " + myFloat);
        System.out.println("double : " + myDouble);

        System.out.println();

        // Narrowing: explicit cast required
        double pi = 3.14159;
        int truncated = (int) pi;    // double → int (truncates decimal)

        double big = 9.99;
        int nine = (int) big;        // 9, NOT 10 (truncation, not rounding)

        long bigLong = 10_000_000_000L;
        int overflow = (int) bigLong; // data loss / overflow

        System.out.println("double  : " + pi);
        System.out.println("(int)pi : " + truncated);
        System.out.println("(int)9.99 : " + nine + "  (not rounded!)");
        System.out.println("(int) 10_000_000_000L : " + overflow + "  (overflow!)");

        // char <-> int
        char ch = 'A';
        int ascii = ch;             // widening: char → int
        char next = (char)(ch + 1); // narrowing: int → char
        System.out.println("\n'A' as int: " + ascii);
        System.out.println("Next char : " + next);
    }
}

public class ArithmeticCasting {
    public static void main(String[] args) {
        int a = 7, b = 2;

        // Integer division — WRONG if you want decimal result
        double result1 = a / b;
        System.out.println("7 / 2 = " + result1);  // 3.0 (integer division then widening)

        // Correct: cast one operand to double first
        double result2 = (double) a / b;
        System.out.println("(double)7 / 2 = " + result2);  // 3.5

        double result3 = a / (double) b;
        System.out.println("7 / (double)2 = " + result3);  // 3.5

        // Using literal
        double result4 = a / 2.0;
        System.out.println("7 / 2.0 = " + result4);  // 3.5

        // Mixing types in expressions
        int x = 10;
        long y = 20L;
        float z = 3.5f;
        double w = 2.0;

        // Result promoted to widest type in expression
        System.out.println("\nx + y = " + (x + y));      // long
        System.out.println("x + z = " + (x + z));       // float
        System.out.println("x + w = " + (x + w));       // double

        // Rounding a double (not truncating)
        double price = 9.75;
        int rounded = (int) Math.round(price); // use Math.round for rounding
        int truncated = (int) price;           // truncates to 9
        System.out.println("\nPrice: " + price);
        System.out.println("Rounded: " + rounded);
        System.out.println("Truncated: " + truncated);
    }
}

public class ObjectCasting {
    // Class hierarchy
    static class Animal {
        String name;
        Animal(String name) { this.name = name; }
        void makeSound() { System.out.println(name + " makes a sound"); }
    }

    static class Dog extends Animal {
        Dog(String name) { super(name); }
        void makeSound() { System.out.println(name + " barks: Woof!"); }
        void fetch() { System.out.println(name + " fetches the ball!"); }
    }

    static class Cat extends Animal {
        Cat(String name) { super(name); }
        void makeSound() { System.out.println(name + " meows: Meow!"); }
        void purr() { System.out.println(name + " purrs..."); }
    }

    public static void main(String[] args) {
        // Upcasting: implicit (Dog -> Animal)
        Animal a1 = new Dog("Rex");  // upcast
        Animal a2 = new Cat("Whiskers"); // upcast

        // Polymorphism: overridden method called
        a1.makeSound(); // Dog's makeSound runs!
        a2.makeSound(); // Cat's makeSound runs!

        // Can't call Dog-specific methods via Animal reference
        // a1.fetch(); // COMPILE ERROR

        // Downcasting with instanceof check
        Animal[] animals = { new Dog("Buddy"), new Cat("Luna"), new Dog("Max") };

        System.out.println();
        for (Animal animal : animals) {
            animal.makeSound();  // polymorphic call

            if (animal instanceof Dog) {
                Dog dog = (Dog) animal;  // safe downcast
                dog.fetch();
            } else if (animal instanceof Cat) {
                Cat cat = (Cat) animal;
                cat.purr();
            }
        }

        // Dangerous: ClassCastException
        System.out.println();
        Animal a = new Dog("Cooper");
        try {
            Cat c = (Cat) a; // ClassCastException: Dog cannot be cast to Cat
        } catch (ClassCastException e) {
            System.out.println("Error: " + e.getMessage());
        }

        System.out.println("a instanceof Dog: " + (a instanceof Dog));  // true
        System.out.println("a instanceof Cat: " + (a instanceof Cat));  // false
    }
}

import java.util.ArrayList;
import java.util.List;

public class ShapeSystem {
    abstract static class Shape {
        String color;
        Shape(String color) { this.color = color; }
        abstract double area();
        void display() {
            System.out.printf("%-12s | Color: %-8s | Area: %.2f%n",
                    getClass().getSimpleName(), color, area());
        }
    }

    static class Circle extends Shape {
        double radius;
        Circle(String color, double radius) {
            super(color);
            this.radius = radius;
        }
        double area() { return Math.PI * radius * radius; }
        void drawCircle() { System.out.println("Drawing circle with radius " + radius); }
    }

    static class Rectangle extends Shape {
        double width, height;
        Rectangle(String color, double width, double height) {
            super(color);
            this.width = width;
            this.height = height;
        }
        double area() { return width * height; }
        void drawRectangle() { System.out.printf("Drawing rectangle %s x %s%n", width, height); }
    }

    static class Triangle extends Shape {
        double base, height;
        Triangle(String color, double base, double height) {
            super(color);
            this.base = base;
            this.height = height;
        }
        double area() { return 0.5 * base * height; }
    }

    public static void main(String[] args) {
        List<Shape> shapes = new ArrayList<>();
        shapes.add(new Circle("Red", 5.0));
        shapes.add(new Rectangle("Blue", 4.0, 6.0));
        shapes.add(new Triangle("Green", 3.0, 8.0));
        shapes.add(new Circle("Yellow", 2.5));
        shapes.add(new Rectangle("Purple", 10.0, 3.0));

        System.out.println("=== All Shapes ===");
        System.out.printf("%-12s | %-16s | %s%n", "Shape", "Color", "Area");
        System.out.println("-".repeat(45));
        for (Shape s : shapes) s.display();  // polymorphism via upcasting

        // Calculate total area - widening cast for sum
        double totalArea = 0;
        for (Shape s : shapes) totalArea += s.area();
        System.out.printf("%nTotal Area: %.2f%n", totalArea);

        // Downcast to access subclass-specific methods
        System.out.println("\n=== Shape-Specific Operations ===");
        for (Shape s : shapes) {
            if (s instanceof Circle circle) {  // Pattern matching (Java 16+)
                circle.drawCircle();
                // Narrowing: double radius to int for display
                int approxRadius = (int) circle.radius;
                System.out.println("  Approx radius (int): " + approxRadius);
            } else if (s instanceof Rectangle rect) {
                rect.drawRectangle();
            }
        }

        // Autoboxing and numeric casting
        System.out.println("\n=== Area Statistics ===");
        List<Double> areas = new ArrayList<>();
        for (Shape s : shapes) areas.add(s.area()); // autoboxing double → Double

        double max = areas.get(0);
        for (Double d : areas) if (d > max) max = d; // unboxing Double → double
        System.out.printf("Largest Area: %.2f%n", max);
        System.out.printf("As integer: %d%n", (int) max); // narrowing cast
    }
}

