import java.util.Scanner;

public class GpaConverter {
    public static double toGpa(double percent) {
        // Narrowing cast to int for range check
        int p = (int) percent;
        if (p >= 90) return 4.0;
        if (p >= 80) return 3.0 + (p - 80) * 0.1;
        if (p >= 70) return 2.0 + (p - 70) * 0.1;
        if (p >= 60) return 1.0 + (p - 60) * 0.1;
        return 0.0;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        double totalGpa = 0;
        for (int i = 0; i < n; i++) {
            String name = sc.next();
            double score = sc.nextDouble();
            sc.nextLine();
            double gpa = toGpa(score);
            totalGpa += gpa;
            System.out.printf("%-7s: %.2f%% -> GPA: %.1f%n", name, score, gpa);
        }
        System.out.printf("Class Average GPA: %.1f%n", totalGpa / n);
        sc.close();
    }
}

import java.util.Scanner;

public class AnimalProcessor {
    static class Animal { String name; Animal(String n) { name = n; } }
    static class Dog extends Animal {
        int barkCount;
        Dog(String n, int b) { super(n); barkCount = b; }
    }
    static class Cat extends Animal {
        int livesRemaining;
        Cat(String n, int l) { super(n); livesRemaining = l; }
    }
    static class Bird extends Animal {
        boolean canFly;
        Bird(String n, boolean f) { super(n); canFly = f; }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        Animal[] animals = new Animal[n];
        for (int i = 0; i < n; i++) {
            String type = sc.next(), name = sc.next();
            if (type.equals("Dog")) animals[i] = new Dog(name, sc.nextInt());
            else if (type.equals("Cat")) animals[i] = new Cat(name, sc.nextInt());
            else animals[i] = new Bird(name, sc.nextBoolean());
            sc.nextLine();
        }
        System.out.println("=== Animal Processing ===");
        int dogs = 0, cats = 0, birds = 0;
        for (Animal a : animals) {
            if (a instanceof Dog dog) { System.out.println("Dog " + dog.name + " - Bark count: " + dog.barkCount); dogs++; }
            else if (a instanceof Cat cat) { System.out.println("Cat " + cat.name + " - Lives remaining: " + cat.livesRemaining); cats++; }
            else if (a instanceof Bird bird) { System.out.println("Bird " + bird.name + " - Can fly: " + bird.canFly); birds++; }
        }
        System.out.println("=== Summary ===");
        System.out.printf("Dogs: %d  Cats: %d  Birds: %d%n", dogs, cats, birds);
        sc.close();
    }
}
